import { useNavigate } from "react-router-dom";

export default function Main(){
    const navigate = useNavigate ();
    return (
        <div className="container">
            <h2>Hovedmeny</h2>
            <button class= "btn btn-menu">Registrer aksjon</button><br></br>
            <button class= "btn btn-menu">Tidligere aksjoner</button>
            <h3>Admin</h3>
      
            <button class= "btn btn-menu color-background: blue" onClick={() => navigate('/user/view')}>Se brukere</button>
            <button class= "btn btn-menu">Legg til bruker</button>
            <br></br>
            <button class= "btn btn-menu">Se aksjoner</button>
            <button class= "btn btn-menu">Legg til aksjon</button>
            <br></br>

            <button class= "btn btn-menu">Mine Innstillinger</button>

        </div>
     )
}
